select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v, postgres.users as u where p.id = pl.postid and p.id = ph.postid and p.id = c.postid and u.id = c.userid and u.id = v.userid and c.creationdate>=timestamp '2010-07-26 20:21:15' and c.creationdate<=timestamp '2014-09-13 01:26:16' and p.score>=-1 and p.score<=19 and p.commentcount<=13 and ph.posthistorytypeid=2 and ph.creationdate<=timestamp '2014-08-07 12:06:00' and v.bountyamount<=50 and v.creationdate>=timestamp '2010-07-21 00:00:00' and v.creationdate<=timestamp '2014-09-14 00:00:00' and u.views>=0 and u.creationdate<=timestamp '2014-08-19 21:33:14';
